// // This is a 1-bit wide, 2-to-1 demultiplexer with a configurable bit-width (default 32 bits). The module selects between two input signals, a and b, based on the value of the select line sel. If sel is low, the output y will be assigned the value of input b; if sel is high, y will take the value of input a.
module top_module( sel, a, b, y );parameter bitwidth=32;
    input sel;
    input  [bitwidth-1:0] a, b;
    output [bitwidth-1:0] y;

    assign y = sel ? b : a;
endmodule
